/**
 * @summary List study materials
 */
export const getListMaterialsUrl = (params) => {
    const normalizedParams = new URLSearchParams();
    Object.entries(params || {}).forEach(([key, value]) => {
        if (value !== undefined) {
            normalizedParams.append(key, value === null ? "null" : value.toString());
        }
    });
    const stringifiedParams = normalizedParams.toString();
    return stringifiedParams.length > 0
        ? `/api/materials?${stringifiedParams}`
        : `/api/materials`;
};
export const listMaterials = async (params, options) => {
    return customFetch(getListMaterialsUrl(params), {
        ...options,
        method: "GET",
    });
};
export const getListMaterialsQueryKey = (params) => {
    return [`/api/materials`, ...(params ? [params] : [])];
};
export const getListMaterialsQueryOptions = (params, options) => {
    const { query: queryOptions, request: requestOptions } = options ?? {};
    const queryKey = queryOptions?.queryKey ?? getListMaterialsQueryKey(params);
    const queryFn = ({ signal, }) => listMaterials(params, { signal, ...requestOptions });
    return { queryKey, queryFn, ...queryOptions };
};
/**
 * @summary List study materials
 */
export function useListMaterials(params, options) {
    const queryOptions = getListMaterialsQueryOptions(params, options);
    const query = useQuery(queryOptions);
    return { ...query, queryKey: queryOptions.queryKey };
}
