export const getMyTransportAssignmentQueryKey = () => ["transport", "my-assignment"];

export const getMyTransportAssignment = async () => {
    const res = await fetch("/api/transport/my-assignment", {
        credentials: "include"
    });
    if (!res.ok) throw new Error("Failed to fetch transport assignment");
    return res.json();
};

export const useGetMyTransportAssignment = (options = {}) => {
    return useQuery({
        queryKey: getMyTransportAssignmentQueryKey(),
        queryFn: getMyTransportAssignment,
        staleTime: 30000,
        ...options,
    });
};

// ─── BOARD / UNBOARD ─────────────────────────────────────────────────────

export const getBoardStudentMutationOptions = (options = {}) => ({
    mutationFn: async ({ studentId, routeId, trip, action = "boarded", location }) => {
        const res = await fetch("/api/transport/board", {
            method: "POST",
            credentials: "include",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ 
                studentId, 
                routeId, 
                trip, 
                action,
                location 
            }),
        });

        const data = await res.json();
        if (!res.ok) throw new Error(data.error || "Failed to update boarding status");
        return data;
    },
    ...options,
});

export const useBoardStudent = (options = {}) => {
    return useMutation(getBoardStudentMutationOptions(options));
};

// Optional: Separate hook if you want cleaner naming
export const useBoardStudentMutation = useBoardStudent;   // alias


