export const getDeleteVendorUrl = (id) => `/api/vendors/${id}`;

export const deleteVendor = async (id, options = {}) => {
    return customFetch(getDeleteVendorUrl(id), {
        ...options,
        method: "DELETE",
    });
};

export const getDeleteVendorMutationOptions = (options = {}) => {
    const mutationKey = ["deleteVendor"];

    const { mutation: mutationOptions, request: requestOptions } = options?.mutation?.mutationKey
        ? options
        : { ...options, mutation: { ...(options?.mutation || {}), mutationKey } };

    const mutationFn = (props) => {
        const { id } = props ?? {};
        if (!id) throw new Error("Vendor ID is required");
        return deleteVendor(id, requestOptions);
    };

    return { mutationFn, ...mutationOptions };
};

